{"id":"3844d365-3b76-4169-a3e9-aeafc52aa151","name":"Next.js Aplikacija sa Azure SQL Autentifikacijom","timestamp":1752502347472,"messages":[{"role":"user","content":[{"type":"text","text":"<user_query>
U pitanju je Next.js projekat! imas punu kontrolu nad projektom i terminalom! Napisi ovo sto mi je claude sonnet rekao:
Odličo! Pomoći ću ti da napraviš jednostavne stranice za prijavljivanje i registrovanje sa Azure SQL konekcijom. Evo kompletnog koda:

## 1. Instaliranje potrebnih paketa

```bash
npm install mssql bcryptjs jsonwebtoken
npm install -D @types/bcryptjs @types/jsonwebtoken
```

## 2. Environment varijable (.env.local)

```env
DEBUG=True
ALLOWED_HOSTS=localhost,127.0.0.1,digitalni-registar-rizika.azurewebsites.net,*.azurewebsites.net
DB_NAME=digitalni_registar_procene_rizika
DB_USER=admin123
DB_PASSWORD=Aleksa2000
DB_HOST=digitalni-registar-procene-rizika.database.windows.net
DB_PORT=1433
JWT_SECRET=tvoj-tajni-kljuc-za-jwt-123456
```

## 3. Baza podataka konekcija (src/lib/db.ts)

```typescript
import sql from 'mssql';

const config: sql.config = {
 user: process.env.DB_USER!,
 password: process.env.DB_PASSWORD!,
 server: process.env.DB_HOST!,
 database: process.env.DB_NAME!,
 port: parseInt(process.env.DB_PORT || '1433'),
 options: {
 encrypt: true,
 trustServerCertificate: false,
 },
};

let pool: sql.ConnectionPool | null = null;

export async function getDbConnection() {
 if (!pool) {
 pool = new sql.ConnectionPool(config);
 await pool.connect();
 }
 return pool;
}

// Kreiranje tabele korisnika
export async function createUsersTable() {
 const pool = await getDbConnection();
 await pool.request().query(`
 IF NOT EXISTS (SELECT * FROM sysobjects WHERE name='korisnici' AND xtype='U')
 CREATE TABLE korisnici (
 id INT IDENTITY(1,1) PRIMARY KEY,
 email NVARCHAR(255) UNIQUE NOT NULL,
 lozinka NVARCHAR(255) NOT NULL,
 ime NVARCHAR(100) NOT NULL,
 prezime NVARCHAR(100) NOT NULL,
 datum_kreiranja DATETIME DEFAULT GETDATE()
 )
 `);
}
```

## 4. API rute za registraciju (src/app/api/registracija/route.ts)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
import { getDbConnection, createUsersTable } from '@/lib/db';

export async function POST(request: NextRequest) {
 try {
 const { email, lozinka, ime, prezime } = await request.json();

 if (!email || !lozinka || !ime || !prezime) {
 return NextResponse.json(
 { greška: 'Sva polja su obavezna' },
 { status: 400 }
 );
 }

 // Kreiranje tabele ako ne postoji
 await createUsersTable();

 const pool = await getDbConnection();

 // Proverava da li korisnik već postoji
 const existingUser = await pool
 .request()
 .input('email', email)
 .query('SELECT * FROM korisnici WHERE email = @email');

 if (existingUser.recordset.length > 0) {
 return NextResponse.json(
 { greška: 'Korisnik sa ovim email-om već postoji' },
 { status: 400 }
 );
 }

 // Hashovanje lozinke
 const hashedPassword = await bcrypt.hash(lozinka, 10);

 // Kreiranje novog korisnika
 await pool
 .request()
 .input('email', email)
 .input('lozinka', hashedPassword)
 .input('ime', ime)
 .input('prezime', prezime)
 .query(`
 INSERT INTO korisnici (email, lozinka, ime, prezime)
 VALUES (@email, @lozinka, @ime, @prezime)
 `);

 return NextResponse.json(
 { poruka: 'Uspešno ste se registrovali!' },
 { status: 201 }
 );
 } catch (error) {
 console.error('Greška pri registraciji:', error);
 return NextResponse.json(
 { greška: 'Došlo je do greške pri registraciji' },
 { status: 500 }
 );
 }
}
```

## 5. API rute za prijavljivanje (src/app/api/prijava/route.ts)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { getDbConnection } from '@/lib/db';

export async function POST(request: NextRequest) {
 try {
 const { email, lozinka } = await request.json();

 if (!email || !lozinka) {
 return NextResponse.json(
 { greška: 'Email i lozinka su obavezni' },
 { status: 400 }
 );
 }

 const pool = await getDbConnection();

 // Pronalaženje korisnika
 const result = await pool
 .request()
 .input('email', email)
 .query('SELECT * FROM korisnici WHERE email = @email');

 if (result.recordset.length === 0) {
 return NextResponse.json(
 { greška: 'Pogrešan email ili lozinka' },
 { status: 401 }
 );
 }

 const korisnik = result.recordset[0];

 // Proverava lozinku
 const isPasswordValid = await bcrypt.compare(lozinka, korisnik.lozinka);

 if (!isPasswordValid) {
 return NextResponse.json(
 { greška: 'Pogrešan email ili lozinka' },
 { status: 401 }
 );
 }

 // Kreiranje JWT tokena
 const token = jwt.sign(
 { 
 id: korisnik.id, 
 email: korisnik.email,
 ime: korisnik.ime,
 prezime: korisnik.prezime
 },
 process.env.JWT_SECRET!,
 { expiresIn: '24h' }
 );

 return NextResponse.json({
 poruka: 'Uspešno ste se prijavili!',
 token,
 korisnik: {
 id: korisnik.id,
 email: korisnik.email,
 ime: korisnik.ime,
 prezime: korisnik.prezime
 }
 });
 } catch (error) {
 console.error('Greška pri prijavi:', error);
 return NextResponse.json(
 { greška: 'Došlo je do greške pri prijavi' },
 { status: 500 }
 );
 }
}
```

## 6. Stranica za registraciju (src/app/registracija/page.tsx)

```typescript
'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';

export default function Registracija() {
 const [formData, setFormData] = useState({
 email: '',
 lozinka: '',
 ime: '',
 prezime: ''
 });
 const [loading, setLoading] = useState(false);
 const [error, setError] = useState('');
 const [success, setSuccess] = useState('');
 const router = useRouter();

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault();
 setLoading(true);
 setError('');
 setSuccess('');

 try {
 const response = await fetch('/api/registracija', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 },
 body: JSON.stringify(formData),
 });

 const data = await response.json();

 if (response.ok) {
 setSuccess('Uspešno ste se registrovali! Možete se prijaviti.');
 setTimeout(() => router.push('/prijava'), 2000);
 } else {
 setError(data.greška || 'Došlo je do greške');
 }
 } catch (err) {
 setError('Došlo je do greške pri slanju zahteva');
 } finally {
 setLoading(false);
 }
 };

 return (
 <div className="min-h-screen flex items-center justify-center bg-gray-50">
 <div className="max-w-md w-full space-y-8">
 <div>
 <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
 Registracija
 </h2>
 </div>
 <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
 <div className="rounded-md shadow-sm -space-y-px">
 <div>
 <input
 type="text"
 required
 className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-gray-900 rounded-t-md focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
 placeholder="Ime"
 value={formData.ime}
 onChange={(e) => setFormData({...formData, ime: e.target.value})}
 />
 </div>
 <div>
 <input
 type="text"
 required
 className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-gray-900 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
 placeholder="Prezime"
 value={formData.prezime}
 onChange={(e) => setFormData({...formData, prezime: e.target.value})}
 />
 </div>
 <div>
 <input
 type="email"
 required
 className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-gray-900 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
 placeholder="Email adresa"
 value={formData.email}
 onChange={(e) => setFormData({...formData, email: e.target.value})}
 />
 </div>
 <div>
 <input
 type="password"
 required
 className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-gray-900 rounded-b-md focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
 placeholder="Lozinka"
 value={formData.lozinka}
 onChange={(e) => setFormData({...formData, lozinka: e.target.value})}
 />
 </div>
 </div>

 {error && (
 <div className="text-red-600 text-sm text-center">{error}</div>
 )}
 {success && (
 <div className="text-green-600 text-sm text-center">{success}</div>
 )}

 <div>
 <button
 type="submit"
 disabled={loading}
 className="group relative w-full flex justify-center py-2 px-4 border border-transparent text-sm font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50"
 >
 {loading ? 'Registracija...' : 'Registruj se'}
 </button>
 </div>

 <div className="text-center">
 <Link href="/prijava" className="text-indigo-600 hover:text-indigo-500">
 Već imate nalog? Prijavite se
 </Link>
 </div>
 </form>
 </div>
 </div>
 );
}
```

## 7. Stranica za prijavljivanje (src/app/prijava/page.tsx)

```typescript
'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';

export default function Prijava() {
 const [formData, setFormData] = useState({
 email: '',
 lozinka: ''
 });
 const [loading, setLoading] = useState(false);
 const [error, setError] = useState('');
 const router = useRouter();

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault();
 setLoading(true);
 setError('');

 try {
 const response = await fetch('/api/prijava', {
 method: 'POST',
 headers: {
 'Content-Type': 'application/json',
 },
 body: JSON.stringify(formData),
 });

 const data = await response.json();

 if (response.ok) {
 // Čuvanje tokena u localStorage
 localStorage.setItem('token', data.token);
 localStorage.setItem('korisnik', JSON.stringify(data.korisnik));

 // Preusmeravanje na početnu stranicu
 router.push('/');
 } else {
 setError(data.greška || 'Došlo je do greške');
 }
 } catch (err) {
 setError('Došlo je do greške pri slanju zahteva');
 } finally {
 setLoading(false);
 }
 };

 return (
 <div className="min-h-screen flex items-center justify-center bg-gray-50">
 <div className="max-w-md w-full space-y-8">
 <div>
 <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
 Prijava
 </h2>
 </div>
 <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
 <div className="rounded-md shadow-sm -space-y-px">
 <div>
 <input
 type="email"
 required
 className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-gray-900 rounded-t-md focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
 placeholder="Email adresa"
 value={formData.email}
 onChange={(e) => setFormData({...formData, email: e.target.value})}
 />
 </div>
 <div>
 <input
 type="password"
 required
 className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-gray-900 rounded-b-md focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
 placeholder="Lozinka"
 value={formData.lozinka}
 onChange={(e) => setFormData({...formData, lozinka: e.target.value})}
 />
 </div>
 </div>

 {error && (
 <div className="text-red-600 text-sm text-center">{error}</div>
 )}

 <div>
 <button
 type="submit"
 disabled={loading}
 className="group relative w-full flex justify-center py-2 px-4 border border-transparent text-sm font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50"
 >
 {loading ? 'Prijavljujem...' : 'Prijavite se'}
 </button>
 </div>

 <div className="text-center">
 <Link href="/registracija" className="text-indigo-600 hover:text-indigo-500">
 Nemate nalog? Registrujte se
 </Link>
 </div>
 </form>
 </div>
 </div>
 );
}
```

## 8. Ažurirana početna stranica (src/app/page.tsx)

```typescript
'use client';
import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';

interface Korisnik {
 id: number;
 email: string;
 ime: string;
 prezime: string;
}

export default function Home() {
 const [korisnik, setKorisnik] = useState<Korisnik | null>(null);
 const router = useRouter();

 useEffect(() => {
 const token = localStorage.getItem('token');
 const korisnikData = localStorage.getItem('korisnik');

 if (token && korisnikData) {
 setKorisnik(JSON.parse(korisnikData));
 }
 }, []);

 const handleLogout = () => {
 localStorage.removeItem('token');
 localStorage.removeItem('korisnik');
 setKorisnik(null);
 router.push('/prijava');
 };

 if (!korisnik) {
 return (
 <div className="min-h-screen flex items-center justify-center bg-gray-50">
 <div className="text-center">
 <h1 className="text-2xl font-bold mb-4">Dobrodošli!</h1>
 <div className="space-x-4">
 <button 
 onClick={() => router.push('/prijava')}
 className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
 >
 Prijava
 </button>
 <button 
 onClick={() => router.push('/registracija')}
 className="bg-green-500 hover:bg-green-700 text-white font-bold py-2 px-4 rounded"
 >
 Registracija
 </button>
 </div>
 </div>
 </div>
 );
 }

 return (
 <div className="min-h-screen bg-gray-50">
 <nav className="bg-white shadow">
 <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
 <div className="flex justify-between h-16">
 <div className="flex items-center">
 <h1 className="text-xl font-semibold">Digitalni Registar</h1>
 </div>
 <div className="flex items-center space-x-4">
 <span>Dobrodošli, {korisnik.ime} {korisnik.prezime}!</span>
 <button
 onClick={handleLogout}
 className="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded"
 >
 Odjava
 </button>
 </div>
 </div>
 </div>
 </nav>

 <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
 <div className="px-4 py-6 sm:px-0">
 <div className="border-4 border-dashed border-gray-200 rounded-lg h-96 p-4">
 <h2 className="text-2xl font-bold mb-4">Početna stranica</h2>
 <p>Ovde možete dodati sadržaj vaše aplikacije...</p>
 </div>
 </div>
 </main>
 </div>
 );
}
```

## Pokretanje aplikacije

1. Instaliraj pakete: `npm install`
2. Pokreni: `npm run dev`
3. Idi na `http://localhost:3000`

Aplikacija će automatski kreirati tabelu `korisnici` u bazi kada se pokrene prvi put. Stranice su na srpskom jeziku i potpuno funkcionalne sa Azure SQL bazom!
