Odradi ovo sto je claude napisao:
Odličo! Dodaću sistem odobrenja administratora. Evo izmena:

## 1. Dodavanje admin tabele i ažuriranje korisnika tabele

Ažuriraj `src/lib/db.ts`:

```typescript
import sql from 'mssql';

const config: sql.config = {
 user: process.env.DB_USER!,
 password: process.env.DB_PASSWORD!,
 server: process.env.DB_HOST!,
 database: process.env.DB_NAME!,
 port: parseInt(process.env.DB_PORT || '1433'),
 options: {
 encrypt: true,
 trustServerCertificate: false,
 },
};

let pool: sql.ConnectionPool | null = null;

export async function getDbConnection() {
 if (!pool) {
 pool = new sql.ConnectionPool(config);
 await pool.connect();
 }
 return pool;
}

// Kreiranje tabele korisnika sa statusom
export async function createUsersTable() {
 const pool = await getDbConnection();

 // Kreiranje tabele korisnika
 await pool.request().query(`
 IF NOT EXISTS (SELECT * FROM sysobjects WHERE name='korisnici' AND xtype='U')
 CREATE TABLE korisnici (
 id INT IDENTITY(1,1) PRIMARY KEY,
 email NVARCHAR(255) UNIQUE NOT NULL,
 lozinka NVARCHAR(255) NOT NULL,
 ime NVARCHAR(100) NOT NULL,
 prezime NVARCHAR(100) NOT NULL,
 status NVARCHAR(20) DEFAULT 'na_cekanju' NOT NULL,
 je_admin BIT DEFAULT 0,
 datum_kreiranja DATETIME DEFAULT GETDATE(),
 datum_odobrenja DATETIME NULL,
 odobrio_admin INT NULL
 )
 `);

 // Proverava da li postoji default admin
 const adminExists = await pool.request().query(`
 SELECT COUNT(*) as count FROM korisnici WHERE je_admin = 1
 `);

 // Ako nema admin-a, kreira default admin-a
 if (adminExists.recordset[0].count === 0) {
 const bcrypt = require('bcryptjs');
 const adminPassword = await bcrypt.hash('admin123', 10);

 await pool.request().query(`
 INSERT INTO korisnici (email, lozinka, ime, prezime, status, je_admin)
 VALUES ('admin@admin.com', '${adminPassword}', 'Admin', 'Administrator', 'odobren', 1)
 `);
 }
}
```

## 2. Ažuriranje registracije API (src/app/api/registracija/route.ts)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
import { getDbConnection, createUsersTable } from '@/lib/db';

export async function POST(request: NextRequest) {
 try {
 const { email, lozinka, ime, prezime } = await request.json();

 if (!email || !lozinka || !ime || !prezime) {
 return NextResponse.json(
 { greška: 'Sva polja su obavezna' },
 { status: 400 }
 );
 }

 // Kreiranje tabele ako ne postoji
 await createUsersTable();

 const pool = await getDbConnection();

 // Proverava da li korisnik već postoji
 const existingUser = await pool
 .request()
 .input('email', email)
 .query('SELECT * FROM korisnici WHERE email = @email');

 if (existingUser.recordset.length > 0) {
 return NextResponse.json(
 { greška: 'Korisnik sa ovim email-om već postoji' },
 { status: 400 }
 );
 }

 // Hashovanje lozinke
 const hashedPassword = await bcrypt.hash(lozinka, 10);

 // Kreiranje novog korisnika sa statusom "na_cekanju"
 await pool
 .request()
 .input('email', email)
 .input('lozinka', hashedPassword)
 .input('ime', ime)
 .input('prezime', prezime)
 .query(`
 INSERT INTO korisnici (email, lozinka, ime, prezime, status)
 VALUES (@email, @lozinka, @ime, @prezime, 'na_cekanju')
 `);

 return NextResponse.json(
 { poruka: 'Uspešno ste se registrovali! Sačekajte odobrenje administratora.' },
 { status: 201 }
 );
 } catch (error) {
 console.error('Greška pri registraciji:', error);
 return NextResponse.json(
 { greška: 'Došlo je do greške pri registraciji' },
 { status: 500 }
 );
 }
}
```

## 3. Ažuriranje prijave API (src/app/api/prijava/route.ts)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { getDbConnection } from '@/lib/db';

export async function POST(request: NextRequest) {
 try {
 const { email, lozinka } = await request.json();

 if (!email || !lozinka) {
 return NextResponse.json(
 { greška: 'Email i lozinka su obavezni' },
 { status: 400 }
 );
 }

 const pool = await getDbConnection();

 // Pronalaženje korisnika
 const result = await pool
 .request()
 .input('email', email)
 .query('SELECT * FROM korisnici WHERE email = @email');

 if (result.recordset.length === 0) {
 return NextResponse.json(
 { greška: 'Pogrešan email ili lozinka' },
 { status: 401 }
 );
 }

 const korisnik = result.recordset[0];

 // Proverava lozinku
 const isPasswordValid = await bcrypt.compare(lozinka, korisnik.lozinka);

 if (!isPasswordValid) {
 return NextResponse.json(
 { greška: 'Pogrešan email ili lozinka' },
 { status: 401 }
 );
 }

 // Proverava status korisnika
 if (korisnik.status === 'na_cekanju') {
 return NextResponse.json(
 { greška: 'Vaš nalog još uvek nije odobren od strane administratora' },
 { status: 403 }
 );
 }

 if (korisnik.status === 'odbačen') {
 return NextResponse.json(
 { greška: 'Vaš nalog je odbačen od strane administratora' },
 { status: 403 }
 );
 }

 // Kreiranje JWT tokena
 const token = jwt.sign(
 { 
 id: korisnik.id, 
 email: korisnik.email,
 ime: korisnik.ime,
 prezime: korisnik.prezime,
 je_admin: korisnik.je_admin
 },
 process.env.JWT_SECRET!,
 { expiresIn: '24h' }
 );

 return NextResponse.json({
 poruka: 'Uspešno ste se prijavili!',
 token,
 korisnik: {
 id: korisnik.id,
 email: korisnik.email,
 ime: korisnik.ime,
 prezime: korisnik.prezime,
 je_admin: korisnik.je_admin
 }
 });
 } catch (error) {
 console.error('Greška pri prijavi:', error);
 return NextResponse.json(
 { greška: 'Došlo je do greške pri prijavi' },
 { status: 500 }
 );
 }
}
```

## 4. API za admin upravljanje (src/app/api/admin/korisnici/route.ts)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import jwt from 'jsonwebtoken';
import { getDbConnection } from '@/lib/db';

// Dobijanje svih korisnika na čekanju
export async function GET(request: NextRequest) {
 try {
 const token = request.headers.get('authorization')?.replace('Bearer ', '');

 if (!token) {
 return NextResponse.json({ greška: 'Nemate dozvolu' }, { status: 401 });
 }

 const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;

 if (!decoded.je_admin) {
 return NextResponse.json({ greška: 'Nemate admin dozvolu' }, { status: 403 });
 }

 const pool = await getDbConnection();
 const result = await pool.request().query(`
 SELECT id, email, ime, prezime, status, datum_kreiranja 
 FROM korisnici 
 WHERE je_admin = 0
 ORDER BY datum_kreiranja DESC
 `);

 return NextResponse.json(result.recordset);
 } catch (error) {
 console.error('Greška:', error);
 return NextResponse.json({ greška: 'Došlo je do greške' }, { status: 500 });
 }
}

// Odobravanje/odbacivanje korisnika
export async function PUT(request: NextRequest) {
 try {
 const token = request.headers.get('authorization')?.replace('Bearer ', '');

 if (!token) {
 return NextResponse.json({ greška: 'Nemate dozvolu' }, { status: 401 });
 }

 const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;

 if (!decoded.je_admin) {
 return NextResponse.json({ greška: 'Nemate admin dozvolu' }, { status: 403 });
 }

 const { korisnikId, status } = await request.json();

 const pool = await getDbConnection();
 await pool.request()
 .input('korisnikId', korisnikId)
 .input('status', status)
 .input('adminId', decoded.id)
 .query(`
 UPDATE korisnici 
 SET status = @status, 
 datum_odobrenja = GETDATE(),
 odobrio_admin = @adminId
 WHERE id = @korisnikId
 `);

 return NextResponse.json({ poruka: 'Uspešno ažurirano' });
 } catch (error) {
 console.error('Greška:', error);
 return NextResponse.json({ greška: 'Došlo je do greške' }, { status: 500 });
 }
}
```

## 5. Admin stranica (src/app/admin/page.tsx)

```typescript
'use client';
import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';

interface Korisnik {
 id: number;
 email: string;
 ime: string;
 prezime: string;
 status: string;
 datum_kreiranja: string;
}

export default function AdminPage() {
 const [korisnici, setKorisnici] = useState<Korisnik[]>([]);
 const [loading, setLoading] = useState(true);
 const router = useRouter();

 useEffect(() => {
 const token = localStorage.getItem('token');
 const korisnikData = localStorage.getItem('korisnik');

 if (!token || !korisnikData) {
 router.push('/prijava');
 return;
 }

 const korisnik = JSON.parse(korisnikData);
 if (!korisnik.je_admin) {
 router.push('/');
 return;
 }

 fetchKorisnici();
 }, [router]);

 const fetchKorisnici = async () => {
 try {
 const token = localStorage.getItem('token');
 const response = await fetch('/api/admin/korisnici', {
 headers: {
 'Authorization': `Bearer ${token}`,
 },
 });

 if (response.ok) {
 const data = await response.json();
 setKorisnici(data);
 }
 } catch (error) {
 console.error('Greška pri učitavanju korisnika:', error);
 } finally {
 setLoading(false);
 }
 };

 const handleStatusChange = async (korisnikId: number, status: string) => {
 try {
 const token = localStorage.getItem('token');
 const response = await fetch('/api/admin/korisnici', {
 method: 'PUT',
 headers: {
 'Content-Type': 'application/json',
 'Authorization': `Bearer ${token}`,
 },
 body: JSON.stringify({ korisnikId, status }),
 });

 if (response.ok) {
 fetchKorisnici(); // Osvežava listu
 }
 } catch (error) {
 console.error('Greška pri ažuriranju statusa:', error);
 }
 };

 const getStatusColor = (status: string) => {
 switch (status) {
 case 'na_cekanju': return 'bg-yellow-100 text-yellow-800';
 case 'odobren': return 'bg-green-100 text-green-800';
 case 'odbačen': return 'bg-red-100 text-red-800';
 default: return 'bg-gray-100 text-gray-800';
 }
 };

 const getStatusText = (status: string) => {
 switch (status) {
 case 'na_cekanju': return 'Na čekanju';
 case 'odobren': return 'Odobren';
 case 'odbačen': return 'Odbačen';
 default: return status;
 }
 };

 if (loading) {
 return <div className="flex justify-center items-center h-screen">Učitavanje...</div>;
 }

 return (
 <div className="min-h-screen bg-gray-50">
 <nav className="bg-white shadow">
 <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
 <div className="flex justify-between h-16">
 <div className="flex items-center">
 <h1 className="text-xl font-semibold">Admin Panel</h1>
 </div>
 <div className="flex items-center">
 <button
 onClick={() => router.push('/')}
 className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded mr-2"
 >
 Početna
 </button>
 <button
 onClick={() => {
 localStorage.clear();
 router.push('/prijava');
 }}
 className="bg-red-500 hover:bg-red-700 text-white font-bold py-2 px-4 rounded"
 >
 Odjava
 </button>
 </div>
 </div>
 </div>
 </nav>

 <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
 <div className="px-4 py-6 sm:px-0">
 <h2 className="text-2xl font-bold mb-6">Upravljanje korisnicima</h2>

 <div className="bg-white shadow overflow-hidden sm:rounded-md">
 <ul className="divide-y divide-gray-200">
 {korisnici.map((korisnik) => (
 <li key={korisnik.id} className="px-6 py-4">
 <div className="flex items-center justify-between">
 <div className="flex-1">
 <div className="flex items-center">
 <div className="flex-shrink-0">
 <div className="h-10 w-10 rounded-full bg-gray-300 flex items-center justify-center">
 <span className="text-sm font-medium text-gray-700">
 {korisnik.ime[0]}{korisnik.prezime[0]}
 </span>
 </div>
 </div>
 <div className="ml-4">
 <div className="text-sm font-medium text-gray-900">
 {korisnik.ime} {korisnik.prezime}
 </div>
 <div className="text-sm text-gray-500">{korisnik.email}</div>
 <div className="text-xs text-gray-400">
 Registrovan: {new Date(korisnik.datum_kreiranja).toLocaleDateString('sr-RS')}
 </div>
 </div>
 </div>
 </div>
 <div className="flex items-center space-x-3">
 <span className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full ${getStatusColor(korisnik.status)}`}>
 {getStatusText(korisnik.status)}
 </span>
 {korisnik.status === 'na_cekanju' && (
 <div className="flex space-x-2">
 <button
 onClick={() => handleStatusChange(korisnik.id, 'odobren')}
 className="bg-green-500 hover:bg-green-700 text-white font-bold py-1 px-3 rounded text-sm"
 >
 Odobri
 </button>
 <button
 onClick={() => handleStatusChange(korisnik.id, 'odbačen')}
 className="bg-red-500 hover:bg-red-700 text-white font-bold py-1 px-3 rounded text-sm"
 >
 Odbaci
 </button>
 </div>
 )}
 </div>
 </div>
 </li>
 ))}
 </ul>
 {korisnici.length === 0 && (
 <div className="text-center py-8 text-gray-500">
 Nema korisnika za prikaz
 </div>
 )}
 </div>
 </div>
 </main>
 </div>
 );
}
```

