import {NextRequest, NextResponse} from 'next/server';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import {getDbConnection} from '../../../lib/db';

export async function POST(request: NextRequest) {
 try {
 const {email, lozinka} = await request.json();

 if (!email || !lozinka) {
 return NextResponse.json(
 {greška: 'Email i lozinka su obavezni'},
 {status: 400}
 );
 }

 const pool = await getDbConnection();

 // Pronalaženje korisnika
 const result = await pool
 .request()
 .input('email', email)
 .query('SELECT * FROM korisnici WHERE email = @email');

 if (result.recordset.length === 0) {
 return NextResponse.json(
 {greška: 'Pogrešan email ili lozinka'},
 {status: 401}
 );
 }

 const korisnik = result.recordset[0];

 // Proverava lozinku
 const isPasswordValid = await bcrypt.compare(lozinka, korisnik.lozinka);

 if (!isPasswordValid) {
 return NextResponse.json(
 {greška: 'Pogrešan email ili lozinka'},
 {status: 401}
 );
 }

 // Kreiranje JWT tokena
 const token = jwt.sign(
 {
 id: korisnik.id,
 email: korisnik.email,
 ime: korisnik.ime,
 prezime: korisnik.prezime
 },
 process.env.JWT_SECRET!,
 {expiresIn: '24h'}
 );

 return NextResponse.json({
 poruka: 'Uspešno ste se prijavili!',
 token,
